import React from "react";
import ReactSlider from "react-slider";

const Filters = ({ yearRange, setYearRange, widthRange, setWidthRange, heightRange, setHeightRange, filterData }) => {
    const handleSliderChange = (values, setRange) => {
        setRange(values);
        filterData();
    };

    return (
        <aside className="filters">
            <h2>Filters</h2>

            {/* Year Range Slider */}
            <div className="filter-section">
                <label>Year Range:</label>
                <ReactSlider
                    className="slider"
                    thumbClassName="thumb"
                    trackClassName="track"
                    value={yearRange}
                    onChange={values => handleSliderChange(values, setYearRange)}
                    min={2011}
                    max={2025}
                    pearling
                    minDistance={1}
                />
                <span>{yearRange[0]} - {yearRange[1]}</span>
            </div>

            {/* Width Slider */}
            <div className="filter-section">
                <label>Width:</label>
                <ReactSlider
                    className="slider"
                    thumbClassName="thumb"
                    trackClassName="track"
                    value={widthRange}
                    onChange={values => handleSliderChange(values, setWidthRange)}
                    min={0}
                    max={100}
                    pearling
                    minDistance={1}
                />
                <span>{widthRange[0]} - {widthRange[1]}</span>
            </div>

            {/* Height Slider */}
            <div className="filter-section">
                <label>Height:</label>
                <ReactSlider
                    className="slider"
                    thumbClassName="thumb"
                    trackClassName="track"
                    value={heightRange}
                    onChange={values => handleSliderChange(values, setHeightRange)}
                    min={0}
                    max={100}
                    pearling
                    minDistance={1}
                />
                <span>{heightRange[0]} - {heightRange[1]}</span>
            </div>
        </aside>
    );
};

export default Filters;
